import * as React from "react"
import { useMemo } from "react"
import {  cva } from "class-variance-authority"

import { cn } from "@nhic/currantui/lib/utils"
import { Label } from "@nhic/currantui/components/label"
import { Separator } from "@nhic/currantui/components/separator"
import type {VariantProps} from "class-variance-authority";

function FieldSet({ className, ...props }: React.ComponentProps<"fieldset">) {
  return (
    <fieldset
      data-slot="field-set"
      className={cn(
        "flex flex-col gap-4 has-[>[data-slot=checkbox-group]]:gap-3 has-[>[data-slot=radio-group]]:gap-3",
        className
      )}
      {...props}
    />
  )
}

function FieldLegend({
  className,
  variant = "legend",
  ...props
}: React.ComponentProps<"legend"> & { variant?: "legend" | "label" }) {
  return (
    <legend
      data-slot="field-legend"
      data-variant={variant}
      className={cn(
        "mb-2 font-medium data-[variant=label]:text-xs/relaxed data-[variant=legend]:text-sm",
        className
      )}
      {...props}
    />
  )
}

function FieldGroup({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="field-group"
      className={cn(
        "group/field-group @container/field-group flex w-full flex-col gap-4 data-[slot=checkbox-group]:gap-3 *:data-[slot=field-group]:gap-4",
        className
      )}
      {...props}
    />
  )
}

const fieldVariants = cva(
  "group/field flex w-full gap-2 data-[invalid=true]:text-destructive",
  {
    variants: {
      orientation: {
        vertical: "flex-col *:w-full [&>.sr-only]:w-auto",
        horizontal:
          "flex-row items-center has-[>[data-slot=field-content]]:items-start *:data-[slot=field-label]:flex-auto has-[>[data-slot=field-content]]:[&>[role=checkbox],[role=radio]]:mt-px",
        responsive:
          "flex-col *:w-full @md/field-group:flex-row @md/field-group:items-center @md/field-group:*:w-auto @md/field-group:has-[>[data-slot=field-content]]:items-start @md/field-group:*:data-[slot=field-label]:flex-auto [&>.sr-only]:w-auto @md/field-group:has-[>[data-slot=field-content]]:[&>[role=checkbox],[role=radio]]:mt-px",
      },
    },
    defaultVariants: {
      orientation: "vertical",
    },
  }
)

function Field({
  className,
  orientation = "vertical",
  ...props
}: React.ComponentProps<"div"> & VariantProps<typeof fieldVariants>) {
  return (
    <div
      role="group"
      data-slot="field"
      data-orientation={orientation}
      className={cn(fieldVariants({ orientation }), className)}
      {...props}
    />
  )
}

function FieldContent({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="field-content"
      className={cn(
        "group/field-content flex flex-1 flex-col gap-0.5 leading-snug",
        className
      )}
      {...props}
    />
  )
}

function FieldLabel({
  className,
  ...props
}: React.ComponentProps<typeof Label>) {
  return (
    <Label
      data-slot="field-label"
      className={cn(
        "group/field-label peer/field-label flex w-fit gap-2 leading-snug group-data-[disabled=true]/field:opacity-50 has-data-checked:bg-primary/5 has-[>[data-slot=field]]:rounded-md has-[>[data-slot=field]]:border *:data-[slot=field]:p-2 dark:has-data-checked:bg-primary/10",
        "has-[>[data-slot=field]]:w-full has-[>[data-slot=field]]:flex-col",
        className
      )}
      {...props}
    />
  )
}

function FieldTitle({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="field-label"
      className={cn(
        "flex w-fit items-center gap-2 text-xs/relaxed font-medium group-data-[disabled=true]/field:opacity-50",
        className
      )}
      {...props}
    />
  )
}

function FieldDescription({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="field-description"
      className={cn(
        "text-start text-xs/relaxed leading-normal font-normal text-muted-foreground group-has-data-horizontal/field:text-balance [[data-variant=legend]+&]:-mt-1.5",
        "last:mt-0 nth-last-2:-mt-1",
        "[&>a]:underline [&>a]:underline-offset-4 [&>a:hover]:text-primary",
        className
      )}
      {...props}
    />
  )
}

function FieldSeparator({
  children,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  children?: React.ReactNode
}) {
  return (
    <div
      data-slot="field-separator"
      data-content={!!children}
      className={cn(
        "relative -my-2 h-5 text-xs/relaxed group-data-[variant=outline]/field-group:-mb-2",
        className
      )}
      {...props}
    >
      <Separator className="absolute inset-0 top-1/2" />
      {children && (
        <span
          className="relative mx-auto block w-fit bg-background px-2 text-muted-foreground"
          data-slot="field-separator-content"
        >
          {children}
        </span>
      )}
    </div>
  )
}

function FieldError({
  className,
  children,
  errors,
  ...props
}: React.ComponentProps<"div"> & {
  errors?: Array<{ message?: string } | undefined>
}) {
  const content = useMemo(() => {
    if (children) {
      return children
    }

    if (!errors?.length) {
      return null
    }

    const uniqueErrors = [
      ...new Map(errors.map((error) => [error?.message, error])).values(),
    ]

    if (uniqueErrors.length === 1) {
      return uniqueErrors[0]?.message
    }

    return (
      <ul className="ms-4 flex list-disc flex-col gap-1">
        {uniqueErrors.map(
          (error, index) =>
            error?.message && <li key={index}>{error.message}</li>
        )}
      </ul>
    )
  }, [children, errors])

  if (!content) {
    return null
  }

  return (
    <div
      role="alert"
      data-slot="field-error"
      className={cn("text-xs/relaxed font-normal text-destructive", className)}
      {...props}
    >
      {content}
    </div>
  )
}

export {
  Field,
  FieldLabel,
  FieldDescription,
  FieldError,
  FieldGroup,
  FieldLegend,
  FieldSeparator,
  FieldSet,
  FieldContent,
  FieldTitle,
}

import * as React from "react"

import {
  CheckCircleIcon,
  FileIcon,
  UploadSimpleIcon,
  XCircleIcon,
  XIcon,
} from "@phosphor-icons/react"
import { ProgressCircle } from "@nhic/currantui/components/progress-circle"
import { DropZone, FileTrigger } from "@nhic/currantui/components/drop-zone"
import { Button } from "@nhic/currantui/components/button"
import { Progress } from "@nhic/currantui/components/progress"
import { cn } from "@nhic/currantui/lib/utils"

interface FileUploaderItem {
  id: string
  name: string
  /** Bytes; rendered human-readable when provided */
  size?: number
  status: "uploading" | "complete" | "error"
  /** 0–100, shown while uploading */
  progress?: number
  errorMessage?: string
}

function formatBytes(bytes: number) {
  if (bytes < 1024) return `${bytes} B`
  const units = ["KB", "MB", "GB"]
  let value = bytes
  let unit = ""
  for (const next of units) {
    value /= 1024
    unit = next
    if (value < 1024) break
  }
  return `${value.toFixed(value >= 10 ? 0 : 1)} ${unit}`
}

function FileUploaderRow({
  item,
  onRemove,
}: {
  item: FileUploaderItem
  onRemove?: (id: string) => void
}) {
  return (
    <li
      data-slot="file-uploader-item"
      data-status={item.status}
      className={cn(
        "flex items-center gap-2 rounded-md border border-border px-2 py-1.5",
        item.status === "error" && "border-destructive/40"
      )}
    >
      <FileIcon
        aria-hidden="true"
        className="size-4 shrink-0 text-muted-foreground"
      />
      <div className="flex min-w-0 flex-1 flex-col gap-1">
        <div className="flex items-baseline gap-2">
          <span className="truncate text-xs/relaxed font-medium">
            {item.name}
          </span>
          {item.size != null && (
            <span className="shrink-0 text-[0.625rem] text-muted-foreground tabular-nums">
              {formatBytes(item.size)}
            </span>
          )}
        </div>
        {item.status === "uploading" && (
          <Progress
            aria-label={`Uploading ${item.name}`}
            value={item.progress ?? null}
            className="h-1"
          />
        )}
        {item.status === "error" && item.errorMessage != null && (
          <span className="text-[0.625rem] text-destructive">
            {item.errorMessage}
          </span>
        )}
      </div>
      {item.status === "uploading" && (
        <ProgressCircle
          aria-hidden="true"
          size="sm"
          className="size-3.5 shrink-0"
        />
      )}
      {item.status === "complete" && (
        <CheckCircleIcon
          weight="fill"
          aria-hidden="true"
          className="size-4 shrink-0 text-success"
        />
      )}
      {item.status === "error" && (
        <XCircleIcon
          weight="fill"
          aria-hidden="true"
          className="size-4 shrink-0 text-destructive"
        />
      )}
      {onRemove && (
        <Button
          variant="ghost"
          size="icon-xs"
          aria-label={`Remove ${item.name}`}
          onClick={() => onRemove(item.id)}
        >
          <XIcon />
        </Button>
      )}
    </li>
  )
}

/**
 * Drop zone + browse button + file list. Purely presentational about
 * transfer: the app owns the network and reports state back through `items`.
 */
function FileUploader({
  items = [],
  onSelect,
  onRemove,
  acceptedFileTypes,
  allowsMultiple = true,
  label = "Drag and drop files here",
  triggerLabel = "Browse files",
  hint,
  className,
  ...props
}: Omit<React.ComponentProps<"div">, "onSelect"> & {
  items?: Array<FileUploaderItem>
  /** Receives files from both drag-and-drop and the browse button */
  onSelect?: (files: Array<File>) => void
  onRemove?: (id: string) => void
  acceptedFileTypes?: Array<string>
  allowsMultiple?: boolean
  label?: React.ReactNode
  triggerLabel?: React.ReactNode
  hint?: React.ReactNode
}) {
  return (
    <div
      data-slot="file-uploader"
      className={cn("flex w-full flex-col gap-2", className)}
      {...props}
    >
      <DropZone
        aria-label={typeof label === "string" ? label : "File drop zone"}
        getDropOperation={(types) =>
          acceptedFileTypes == null ||
          acceptedFileTypes.some((type) => types.has(type))
            ? "copy"
            : "cancel"
        }
        onDrop={(event) => {
          const fileItems = event.items.filter(
            (item) => item.kind === "file"
          )
          void Promise.all(fileItems.map((item) => item.getFile())).then(
            (files) => {
              if (files.length > 0) {
                onSelect?.(allowsMultiple ? files : files.slice(0, 1))
              }
            }
          )
        }}
      >
        <UploadSimpleIcon aria-hidden="true" className="size-5" />
        <span>{label}</span>
        <FileTrigger
          acceptedFileTypes={acceptedFileTypes}
          allowsMultiple={allowsMultiple}
          onSelect={(fileList) => {
            if (fileList && fileList.length > 0) {
              onSelect?.(Array.from(fileList))
            }
          }}
        >
          {triggerLabel}
        </FileTrigger>
        {hint != null && (
          <span className="text-[0.625rem] text-muted-foreground">{hint}</span>
        )}
      </DropZone>
      {items.length > 0 && (
        <ul
          data-slot="file-uploader-list"
          className="flex flex-col gap-1.5"
          aria-label="Selected files"
        >
          {items.map((item) => (
            <FileUploaderRow key={item.id} item={item} onRemove={onRemove} />
          ))}
        </ul>
      )}
    </div>
  )
}

export { FileUploader }
export type { FileUploaderItem }

