import * as React from "react"

import { useIsMobile } from "@nhic/currantui/hooks/use-mobile"
import { cn } from "@nhic/currantui/lib/utils"

const SHELL_COOKIE_NAME = "currantui_shell_sidenav"
const SHELL_COOKIE_MAX_AGE = 60 * 60 * 24 * 365

/* z-index ladder: content auto → side nav rail overlay z-30 → header + right
   panels z-40 → dialogs/sheets/popovers/tooltips z-50 → skip link z-60 */

type ShellContextValue = {
  /** Desktop side-nav expanded state (expandable variant) */
  open: boolean
  setOpen: (open: boolean) => void
  /** Mobile (max-lg) overlay open state */
  openMobile: boolean
  setOpenMobile: (open: boolean) => void
  isMobile: boolean
  /** Branches on isMobile; wired to ShellHeaderMenuButton and Mod+B */
  toggleSideNav: () => void
  /** Exclusive right-panel state — a single id keeps one panel open at a time */
  activePanel: string | null
  setActivePanel: React.Dispatch<React.SetStateAction<string | null>>
  togglePanel: (id: string) => void
}

const ShellContext = React.createContext<ShellContextValue | null>(null)

function useShell() {
  const context = React.useContext(ShellContext)
  if (!context) {
    throw new Error("useShell must be used within a ShellProvider.")
  }
  return context
}

function ShellProvider({
  defaultOpen = true,
  open: openProp,
  onOpenChange,
  keyboardShortcut = true,
  className,
  style,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  /** Uncontrolled initial state; SSR apps hydrate it from the SHELL_COOKIE_NAME cookie */
  defaultOpen?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
  /** Mod+B toggles the side nav */
  keyboardShortcut?: boolean
}) {
  const isMobile = useIsMobile()
  const [openMobile, setOpenMobile] = React.useState(false)
  const [openState, setOpenState] = React.useState(defaultOpen)
  const open = openProp ?? openState

  const setOpen = React.useCallback(
    (next: boolean) => {
      if (openProp === undefined) setOpenState(next)
      onOpenChange?.(next)
      document.cookie = `${SHELL_COOKIE_NAME}=${next}; path=/; max-age=${SHELL_COOKIE_MAX_AGE}`
    },
    [openProp, onOpenChange]
  )

  const toggleSideNav = React.useCallback(() => {
    if (isMobile) {
      setOpenMobile((prev) => !prev)
    } else {
      setOpen(!open)
    }
  }, [isMobile, open, setOpen])

  const [activePanel, setActivePanel] = React.useState<string | null>(null)
  const togglePanel = React.useCallback((id: string) => {
    setActivePanel((prev) => (prev === id ? null : id))
  }, [])

  React.useEffect(() => {
    if (!keyboardShortcut) return
    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key === "b" && (event.metaKey || event.ctrlKey)) {
        event.preventDefault()
        toggleSideNav()
      }
    }
    window.addEventListener("keydown", onKeyDown)
    return () => window.removeEventListener("keydown", onKeyDown)
  }, [keyboardShortcut, toggleSideNav])

  const contextValue = React.useMemo<ShellContextValue>(
    () => ({
      open,
      setOpen,
      openMobile,
      setOpenMobile,
      isMobile,
      toggleSideNav,
      activePanel,
      setActivePanel,
      togglePanel,
    }),
    [open, setOpen, openMobile, isMobile, toggleSideNav, activePanel, togglePanel]
  )

  return (
    <ShellContext.Provider value={contextValue}>
      <div
        data-slot="shell"
        data-state={open ? "expanded" : "collapsed"}
        style={
          {
            "--shell-header-h": "3rem",
            "--shell-sidenav-w": "16rem",
            "--shell-sidenav-w-rail": "3rem",
            ...style,
          } as React.CSSProperties
        }
        className={cn(
          "group/shell grid min-h-svh grid-cols-[auto_minmax(0,1fr)] grid-rows-[auto_1fr] bg-background",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </ShellContext.Provider>
  )
}

function ShellContent({ className, ...props }: React.ComponentProps<"main">) {
  return (
    <main
      id="main-content"
      tabIndex={-1}
      data-slot="shell-content"
      className={cn("col-start-2 row-start-2 min-w-0 outline-none", className)}
      {...props}
    />
  )
}

function ShellSkipToContent({
  href = "#main-content",
  children = "Skip to main content",
  className,
  ...props
}: React.ComponentProps<"a">) {
  return (
    <a
      href={href}
      data-slot="shell-skip-to-content"
      className={cn(
        "sr-only focus-visible:not-sr-only focus-visible:fixed focus-visible:start-2 focus-visible:top-2 focus-visible:z-60 focus-visible:flex focus-visible:h-7 focus-visible:items-center focus-visible:rounded-md focus-visible:bg-primary focus-visible:px-2 focus-visible:text-xs/relaxed focus-visible:font-medium focus-visible:text-primary-foreground focus-visible:ring-2 focus-visible:ring-ring/30 focus-visible:outline-none",
        className
      )}
      {...props}
    >
      {children}
    </a>
  )
}

export { ShellProvider, useShell, ShellContent, ShellSkipToContent, SHELL_COOKIE_NAME }

import * as React from "react"
import { Slot } from "radix-ui"

import { CaretDownIcon, ListIcon, XIcon } from "@phosphor-icons/react"
import { useShell } from "@nhic/currantui/components/shell"
import { cn } from "@nhic/currantui/lib/utils"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@nhic/currantui/components/dropdown-menu"
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@nhic/currantui/components/tooltip"

const headerNavLinkClasses =
  "flex h-8 items-center gap-1 rounded-md px-2 text-xs/relaxed text-sidebar-foreground/70 transition-colors outline-none hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 focus-visible:ring-ring/30 data-active:font-medium data-active:text-sidebar-foreground [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-3.5"

const globalActionClasses =
  "relative flex size-8 shrink-0 items-center justify-center rounded-md text-sidebar-foreground/60 transition-colors outline-none hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 focus-visible:ring-ring/30 disabled:pointer-events-none disabled:opacity-50 data-active:bg-sidebar-accent data-active:text-sidebar-accent-foreground [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4"

function ShellHeader({ className, ...props }: React.ComponentProps<"header">) {
  const ref = React.useRef<HTMLElement>(null)

  /* The header grows with its content (tall brand lockups, wrapped nav) —
     write the measured height back to --shell-header-h so the side nav and
     panels stay offset correctly. min-h keeps this loop-free: raising the
     variable never changes the measured content height. */
  React.useEffect(() => {
    const el = ref.current
    const shell = el?.closest<HTMLElement>('[data-slot="shell"]')
    if (!el || !shell) return
    const sync = () =>
      shell.style.setProperty("--shell-header-h", `${el.offsetHeight}px`)
    sync()
    const observer = new ResizeObserver(sync)
    observer.observe(el)
    return () => {
      observer.disconnect()
      shell.style.removeProperty("--shell-header-h")
    }
  }, [])

  return (
    <header
      ref={ref}
      data-slot="shell-header"
      className={cn(
        "sticky top-0 z-40 col-span-full row-start-1 flex min-h-(--shell-header-h) items-center gap-1 border-b border-sidebar-border bg-sidebar px-2 py-1.5 text-sidebar-foreground",
        className
      )}
      {...props}
    />
  )
}

function ShellHeaderMenuButton({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { open, openMobile, isMobile, toggleSideNav } = useShell()
  const expanded = isMobile ? openMobile : open

  return (
    <button
      type="button"
      data-slot="shell-header-menu-button"
      aria-label={expanded ? "Close navigation" : "Open navigation"}
      aria-expanded={expanded}
      aria-controls="shell-side-nav"
      onClick={toggleSideNav}
      className={cn(globalActionClasses, className)}
      {...props}
    >
      {expanded ? <XIcon /> : <ListIcon />}
    </button>
  )
}

/**
 * Brand slot of the header. Children can be plain text, `HicLogo`, or any
 * custom lockup — descendant images/SVGs are clamped to the header height.
 */
function ShellHeaderName({
  asChild = false,
  className,
  ...props
}: React.ComponentProps<"a"> & { asChild?: boolean }) {
  const Comp = asChild ? Slot.Root : "a"

  return (
    <Comp
      data-slot="shell-header-name"
      className={cn(
        "flex items-center gap-2 rounded-md px-1 font-heading text-sm font-semibold tracking-tight whitespace-nowrap outline-none focus-visible:ring-2 focus-visible:ring-ring/30 [&_img]:max-h-8 [&_img]:w-auto [&_svg:not([class*='size-'])]:max-h-8",
        className
      )}
      {...props}
    />
  )
}

function ShellHeaderNav({
  className,
  children,
  ...props
}: React.ComponentProps<"nav">) {
  return (
    <nav
      aria-label="Primary"
      data-slot="shell-header-nav"
      // -my-1.5 cancels the header's py-1.5 so the nav spans border to
      // border and the active bar can sit exactly on the header's bottom edge
      className={cn("-my-1.5 ms-2 self-stretch max-lg:hidden", className)}
      {...props}
    >
      <ul className="flex h-full items-stretch gap-0.5">{children}</ul>
    </nav>
  )
}

function ShellHeaderNavLink({
  asChild = false,
  isActive = false,
  className,
  ...props
}: React.ComponentProps<"a"> & { asChild?: boolean; isActive?: boolean }) {
  const Comp = asChild ? Slot.Root : "a"

  return (
    <li data-slot="shell-header-nav-item" className="relative flex">
      <Comp
        data-slot="shell-header-nav-link"
        data-active={isActive || undefined}
        aria-current={isActive ? "page" : undefined}
        className={cn(
          headerNavLinkClasses,
          "h-full data-active:after:absolute data-active:after:inset-x-2 data-active:after:bottom-0 data-active:after:h-0.5 data-active:after:bg-sidebar-primary",
          className
        )}
        {...props}
      />
    </li>
  )
}

function ShellHeaderNavMenu({
  label,
  className,
  children,
  ...props
}: React.ComponentProps<"li"> & { label: string }) {
  return (
    <li data-slot="shell-header-nav-menu" className="flex" {...props}>
      <DropdownMenu>
        <DropdownMenuTrigger
          className={cn(
            headerNavLinkClasses,
            "h-full aria-expanded:bg-sidebar-accent aria-expanded:text-sidebar-accent-foreground [&_svg]:transition-transform aria-expanded:[&_svg]:rotate-180",
            className
          )}
        >
          {label}
          <CaretDownIcon />
        </DropdownMenuTrigger>
        <DropdownMenuContent align="start">{children}</DropdownMenuContent>
      </DropdownMenu>
    </li>
  )
}

function ShellHeaderNavMenuItem({
  asChild = false,
  isActive = false,
  children,
  ...props
}: React.ComponentProps<typeof DropdownMenuItem> & { isActive?: boolean }) {
  return (
    <DropdownMenuItem
      asChild={asChild}
      data-slot="shell-header-nav-menu-item"
      aria-current={isActive ? "page" : undefined}
      {...props}
    >
      {children}
    </DropdownMenuItem>
  )
}

function ShellGlobalBar({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="shell-global-bar"
      className={cn("ms-auto flex items-center gap-1", className)}
      {...props}
    />
  )
}

function ShellGlobalAction({
  label,
  panelId,
  className,
  children,
  onClick,
  ...props
}: React.ComponentProps<"button"> & {
  /** Accessible name, also shown as the tooltip */
  label: string
  /** Wires the action to a ShellPanel with the same id (toggle + aria-expanded) */
  panelId?: string
}) {
  const { activePanel, togglePanel } = useShell()
  const active = panelId !== undefined && activePanel === panelId

  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <button
            type="button"
            data-slot="shell-global-action"
            data-active={active || undefined}
            data-shell-panel-trigger={panelId}
            aria-label={label}
            aria-expanded={panelId !== undefined ? active : undefined}
            aria-controls={
              panelId !== undefined ? `shell-panel-${panelId}` : undefined
            }
            onClick={(event) => {
              onClick?.(event)
              if (panelId !== undefined && !event.defaultPrevented) {
                togglePanel(panelId)
              }
            }}
            className={cn(globalActionClasses, className)}
            {...props}
          >
            {children}
          </button>
        </TooltipTrigger>
        <TooltipContent side="bottom">{label}</TooltipContent>
      </Tooltip>
    </TooltipProvider>
  )
}

export {
  ShellHeader,
  ShellHeaderMenuButton,
  ShellHeaderName,
  ShellHeaderNav,
  ShellHeaderNavLink,
  ShellHeaderNavMenu,
  ShellHeaderNavMenuItem,
  ShellGlobalBar,
  ShellGlobalAction,
}

import * as React from "react"
import { Dialog as DialogPrimitive, Slot } from "radix-ui"

import { useShell } from "@nhic/currantui/components/shell"
import { cn } from "@nhic/currantui/lib/utils"

function ShellPanel({
  id,
  label,
  className,
  children,
  ...props
}: Omit<React.ComponentProps<typeof DialogPrimitive.Content>, "id"> & {
  /** Pairs the panel with the ShellGlobalAction carrying the same panelId */
  id: string
  /** Accessible name of the panel dialog */
  label: string
}) {
  const { activePanel, setActivePanel } = useShell()

  return (
    <DialogPrimitive.Root
      open={activePanel === id}
      onOpenChange={(next) => {
        // A close event only clears the state this panel still owns —
        // otherwise panel A's deferred dismiss clobbers a just-opened panel B
        setActivePanel((prev) => (next ? id : prev === id ? null : prev))
      }}
      modal={false}
    >
      <DialogPrimitive.Content
        id={`shell-panel-${id}`}
        data-slot="shell-panel"
        aria-describedby={undefined}
        onInteractOutside={(event) => {
          // Let the owning trigger's own click handle the toggle, otherwise
          // dismiss-then-reopen makes the trigger a no-op
          const target = event.target as Element | null
          if (target?.closest(`[data-shell-panel-trigger="${id}"]`)) {
            event.preventDefault()
          }
        }}
        className={cn(
          "fixed top-(--shell-header-h) bottom-0 z-40 flex w-(--shell-sidenav-w) flex-col overflow-y-auto border-s border-sidebar-border bg-sidebar text-sidebar-foreground shadow-lg outline-none inset-e-0 duration-200 data-open:animate-in data-open:fade-in-0 data-open:slide-in-from-right-10 rtl:data-open:slide-in-from-left-10 data-closed:animate-out data-closed:fade-out-0 data-closed:slide-out-to-right-10 rtl:data-closed:slide-out-to-left-10",
          className
        )}
        {...props}
      >
        <DialogPrimitive.Title className="sr-only">
          {label}
        </DialogPrimitive.Title>
        {children}
      </DialogPrimitive.Content>
    </DialogPrimitive.Root>
  )
}

function ShellSwitcher({ className, ...props }: React.ComponentProps<"ul">) {
  return (
    <ul
      data-slot="shell-switcher"
      className={cn("flex flex-col gap-0.5 p-2", className)}
      {...props}
    />
  )
}

function ShellSwitcherItem({
  asChild = false,
  isActive = false,
  className,
  ...props
}: React.ComponentProps<"a"> & { asChild?: boolean; isActive?: boolean }) {
  const Comp = asChild ? Slot.Root : "a"

  return (
    <li data-slot="shell-switcher-item" className="flex">
      <Comp
        data-slot="shell-switcher-link"
        data-active={isActive || undefined}
        aria-current={isActive ? "page" : undefined}
        className={cn(
          "flex h-7 w-full items-center gap-2 rounded-md px-2 text-xs/relaxed text-sidebar-foreground/70 transition-colors outline-none hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 focus-visible:ring-ring/30 data-active:font-medium data-active:text-sidebar-foreground [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
          className
        )}
        {...props}
      />
    </li>
  )
}

function ShellSwitcherDivider({
  className,
  ...props
}: React.ComponentProps<"li">) {
  return (
    <li
      aria-hidden="true"
      data-slot="shell-switcher-divider"
      className={cn("mx-2 my-1 h-px bg-sidebar-border", className)}
      {...props}
    />
  )
}

export { ShellPanel, ShellSwitcher, ShellSwitcherItem, ShellSwitcherDivider }

import * as React from "react"
import { Collapsible, Dialog as DialogPrimitive, Slot } from "radix-ui"

import { CaretDownIcon, XIcon } from "@phosphor-icons/react"
import { useShell } from "@nhic/currantui/components/shell"
import { cn } from "@nhic/currantui/lib/utils"

const sideNavRowClasses =
  "flex h-7 w-full items-center gap-2 rounded-md px-2 text-start text-xs/relaxed text-sidebar-foreground/70 transition-colors outline-none hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 focus-visible:ring-ring/30 data-active:bg-sidebar-accent data-active:font-medium data-active:text-sidebar-accent-foreground [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4"

function ShellSideNav({
  variant = "expandable",
  label = "Side navigation",
  className,
  children,
  ...props
}: React.ComponentProps<"nav"> & {
  variant?: "expandable" | "rail" | "fixed"
  label?: string
}) {
  const { openMobile, setOpenMobile, isMobile } = useShell()

  return (
    <>
      <nav
        id="shell-side-nav"
        aria-label={label}
        data-slot="shell-side-nav"
        data-variant={variant}
        className={cn(
          "group/side-nav sticky top-(--shell-header-h) col-start-1 row-start-2 z-30 h-[calc(100svh-var(--shell-header-h))] bg-sidebar text-sidebar-foreground",
          variant === "expandable" &&
            "w-(--shell-sidenav-w) overflow-hidden border-e border-sidebar-border transition-[width] duration-200 group-data-[state=collapsed]/shell:w-0 group-data-[state=collapsed]/shell:border-e-0 max-lg:hidden",
          variant === "fixed" &&
            "w-(--shell-sidenav-w) border-e border-sidebar-border",
          variant === "rail" && "w-(--shell-sidenav-w-rail)",
          className
        )}
        {...props}
      >
        <div
          data-slot="shell-side-nav-inner"
          className={cn(
            "flex h-full flex-col overflow-x-hidden overflow-y-auto py-2",
            variant === "rail"
              ? "absolute inset-y-0 start-0 w-(--shell-sidenav-w-rail) border-e border-sidebar-border bg-sidebar shadow-none transition-[width] duration-150 hover:w-(--shell-sidenav-w) hover:shadow-lg focus-within:w-(--shell-sidenav-w) focus-within:shadow-lg"
              : "w-(--shell-sidenav-w)"
          )}
        >
          {children}
        </div>
      </nav>
      {variant === "expandable" && (
        <DialogPrimitive.Root
          open={isMobile && openMobile}
          onOpenChange={setOpenMobile}
        >
          <DialogPrimitive.Overlay
            data-slot="shell-side-nav-overlay"
            className="fixed inset-0 z-50 bg-black/80 duration-100 data-open:animate-in data-open:fade-in-0 data-closed:animate-out data-closed:fade-out-0"
          />
          <DialogPrimitive.Content
            data-slot="shell-side-nav-mobile"
            aria-describedby={undefined}
            className="fixed inset-y-0 start-0 z-50 flex w-(--shell-sidenav-w) flex-col border-e border-sidebar-border bg-sidebar text-sidebar-foreground shadow-lg outline-none duration-200 data-open:animate-in data-open:fade-in-0 data-open:slide-in-from-left-10 rtl:data-open:slide-in-from-right-10 data-closed:animate-out data-closed:fade-out-0 data-closed:slide-out-to-left-10 rtl:data-closed:slide-out-to-right-10"
          >
            <DialogPrimitive.Title className="sr-only">
              {label}
            </DialogPrimitive.Title>
            <div className="flex h-(--shell-header-h) shrink-0 items-center justify-end border-b border-sidebar-border px-2">
              <DialogPrimitive.Close
                className="flex size-8 items-center justify-center rounded-md text-sidebar-foreground/60 transition-colors outline-none hover:bg-sidebar-accent hover:text-sidebar-accent-foreground focus-visible:ring-2 focus-visible:ring-ring/30"
                aria-label="Close navigation"
              >
                <XIcon className="size-4" />
              </DialogPrimitive.Close>
            </div>
            <div className="flex min-h-0 flex-1 flex-col overflow-y-auto py-2">
              {children}
            </div>
          </DialogPrimitive.Content>
        </DialogPrimitive.Root>
      )}
    </>
  )
}

function ShellSideNavItems({ className, ...props }: React.ComponentProps<"ul">) {
  return (
    <ul
      data-slot="shell-side-nav-items"
      className={cn("flex min-h-0 flex-1 flex-col gap-0.5 px-2", className)}
      {...props}
    />
  )
}

function ShellSideNavLink({
  asChild = false,
  isActive = false,
  icon,
  className,
  children,
  ...props
}: React.ComponentProps<"a"> & {
  asChild?: boolean
  isActive?: boolean
  icon?: React.ReactNode
}) {
  const Comp = asChild ? Slot.Root : "a"

  return (
    <li data-slot="shell-side-nav-item" className="flex">
      <Comp
        data-slot="shell-side-nav-link"
        data-active={isActive || undefined}
        aria-current={isActive ? "page" : undefined}
        className={cn(sideNavRowClasses, className)}
        {...props}
      >
        {icon && (
          <span
            aria-hidden="true"
            className="flex size-4 shrink-0 items-center justify-center"
          >
            {icon}
          </span>
        )}
        <span className="truncate">{children}</span>
      </Comp>
    </li>
  )
}

function ShellSideNavMenu({
  label,
  icon,
  defaultOpen,
  open,
  onOpenChange,
  className,
  children,
  ...props
}: React.ComponentProps<"li"> & {
  label: string
  icon?: React.ReactNode
  defaultOpen?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
}) {
  return (
    <li data-slot="shell-side-nav-menu" className="flex flex-col" {...props}>
      <Collapsible.Root
        defaultOpen={defaultOpen}
        open={open}
        onOpenChange={onOpenChange}
        className="flex flex-col gap-0.5"
      >
        <Collapsible.Trigger
          data-slot="shell-side-nav-menu-trigger"
          className={cn(
            sideNavRowClasses,
            "group/side-nav-menu [&_svg]:transition-transform",
            className
          )}
        >
          {icon && (
            <span
              aria-hidden="true"
              className="flex size-4 shrink-0 items-center justify-center"
            >
              {icon}
            </span>
          )}
          <span className="flex-1 truncate">{label}</span>
          <CaretDownIcon className="size-3.5! text-sidebar-foreground/50 group-data-open/side-nav-menu:rotate-180" />
        </Collapsible.Trigger>
        <Collapsible.Content data-slot="shell-side-nav-menu-content" asChild>
          <ul className="flex flex-col gap-0.5">{children}</ul>
        </Collapsible.Content>
      </Collapsible.Root>
    </li>
  )
}

function ShellSideNavMenuItem({
  asChild = false,
  isActive = false,
  className,
  ...props
}: React.ComponentProps<"a"> & { asChild?: boolean; isActive?: boolean }) {
  const Comp = asChild ? Slot.Root : "a"

  return (
    <li data-slot="shell-side-nav-menu-item" className="flex">
      <Comp
        data-slot="shell-side-nav-menu-link"
        data-active={isActive || undefined}
        aria-current={isActive ? "page" : undefined}
        className={cn(sideNavRowClasses, "ps-8", className)}
        {...props}
      />
    </li>
  )
}

function ShellSideNavDivider({
  className,
  ...props
}: React.ComponentProps<"li">) {
  return (
    <li
      aria-hidden="true"
      data-slot="shell-side-nav-divider"
      className={cn("mx-2 my-1 h-px shrink-0 bg-sidebar-border", className)}
      {...props}
    />
  )
}

function ShellSideNavFooter({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="shell-side-nav-footer"
      className={cn(
        "mt-auto border-t border-sidebar-border px-2 pt-2",
        className
      )}
      {...props}
    />
  )
}

export {
  ShellSideNav,
  ShellSideNavItems,
  ShellSideNavLink,
  ShellSideNavMenu,
  ShellSideNavMenuItem,
  ShellSideNavDivider,
  ShellSideNavFooter,
}

import { Tooltip } from "radix-ui"
import type { ReactElement } from "react"

interface SidebarItemProps {
  label: string
  children: ReactElement
}

/** @deprecated Use `ShellSideNavLink` from `@nhic/currantui/components/shell-side-nav` (the rail variant reveals labels by expansion instead of tooltips) — removal planned for the next major. */
export function SidebarItem({ label, children }: SidebarItemProps) {
  return (
    <Tooltip.Provider delayDuration={300}>
