        <ToggletipContent aria-label="Stockout definition">
          <ToggletipBody>
            Any tracer commodity unavailable for one full day or more during
            the reporting period.
          </ToggletipBody>
        </ToggletipContent>
      </Toggletip>
    </div>
  ),
}

