import {
  FilterChip,
  filterChipVariants,
} from "@nhic/currantui/components/filter-chip";
import { SearchField } from "@nhic/currantui/components/search-field";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@nhic/currantui/components/select";
import { SortIndicator } from "@nhic/currantui/components/sort-indicator";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@nhic/currantui/components/table";
import { TableEmptyState } from "@nhic/currantui/components/table-empty-state";
import {
  TableToolbar,
  TableToolbarLabel,
  TableToolbarSeparator,
} from "@nhic/currantui/components/table-toolbar";
import { TablePagination } from "@nhic/currantui/components/table-pagination";
import {
  TableSelectionBar,
  blurFocusedRowControl,
} from "@nhic/currantui/components/table-selection-bar";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@nhic/currantui/components/tooltip";
import { exportRowsToCsv } from "@nhic/currantui/lib/export-csv";
import { cn } from "@nhic/currantui/lib/utils";

import type {
  ColumnDef,
  PaginationState,
  SortingState,
} from "@tanstack/react-table";
import type { Meta, StoryObj } from "@storybook/react-vite";

/* Placeholder domain — replace with your own row type */
interface Report {
