export interface CsvColumn<T> {
  header: string
  value: (row: T) => unknown
}

function toCell(value: unknown): string {
  if (value == null) return ""
  const text = Array.isArray(value) ? value.join("+") : String(value)
  return /[",\n\r]/.test(text) ? `"${text.replaceAll('"', '""')}"` : text
}

/** Serialize rows to CSV and trigger a browser download */
export function exportRowsToCsv<T>(
  rows: Array<T>,
  columns: Array<CsvColumn<T>>,
  filename: string,
): void {
  const csv = [
    columns.map((c) => toCell(c.header)).join(","),
    ...rows.map((row) => columns.map((c) => toCell(c.value(row))).join(",")),
  ].join("\n")

  const url = URL.createObjectURL(new Blob([csv], { type: "text/csv" }))
  const a = document.createElement("a")
  a.href = url
  a.download = filename.endsWith(".csv") ? filename : `${filename}.csv`
  a.click()
  URL.revokeObjectURL(url)
}

import {  clsx } from "clsx"
import { twMerge } from "tailwind-merge"
import type {ClassValue} from "clsx";

export function cn(...inputs: Array<ClassValue>) {
  return twMerge(clsx(inputs))
}

import * as React from "react"

/* Matches Tailwind's `max-lg:` exactly so CSS and JS agree on the breakpoint */
const MOBILE_QUERY = "(max-width: 1023px)"

function subscribe(callback: () => void) {
  const mql = window.matchMedia(MOBILE_QUERY)
  mql.addEventListener("change", callback)
  return () => mql.removeEventListener("change", callback)
}

function useIsMobile() {
  return React.useSyncExternalStore(
    subscribe,
    () => window.matchMedia(MOBILE_QUERY).matches,
    () => false
  )
}

export { useIsMobile }
